// Evidence: httpsts-outbox-consistency-1lj7a2
// Competency: httpsts-outbox-consistency.
// Case 6316: multi-tenant case service with a bounded PostgreSQL pool.
// Operating constraint: distinguish proxy evidence from origin evidence.
// Changed case: remove one trusted proxy hop and recompute authority from the socket boundary.
function evidence_httpsts_outbox_consistency_1lj7a2(fingerprintMatches: boolean, expectedVersion: number, actualVersion: number, outboxStored: boolean): { status: number; decision: string; publish: boolean } {
  if (!fingerprintMatches) return { status: 409, decision: "idempotency-mismatch", publish: false };
  if (expectedVersion !== actualVersion) {
    return { status: 412, decision: "version-conflict", publish: false };
  }
  return { status: outboxStored ? 200 : 503, decision: "updated", publish: outboxStored };
}
